/**
 * @summary Get a specific audit report
 */
export const getGetReportUrl = (reportId: number) => {
  return `/api/reports/${reportId}`;
};

export const getReport = async (
  reportId: number,
  options?: RequestInit,
): Promise<AuditReport> => {
  return customFetch<AuditReport>(getGetReportUrl(reportId), {
    ...options,
    method: "GET",
  });
};

export const getGetReportQueryKey = (reportId: number) => {
  return [`/api/reports/${reportId}`] as const;
};

export const getGetReportQueryOptions = <
  TData = Awaited<ReturnType<typeof getReport>>,
  TError = ErrorType<unknown>,
>(
  reportId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getReport>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetReportQueryKey(reportId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getReport>>> = ({
    signal,
  }) => getReport(reportId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!reportId,
    ...queryOptions,
  } as UseQueryOptions<Awaited<ReturnType<typeof getReport>>, TError, TData> & {
    queryKey: QueryKey;
  };
};

export type GetReportQueryResult = NonNullable<
  Awaited<ReturnType<typeof getReport>>
>;
export type GetReportQueryError = ErrorType<unknown>;

/**
 * @summary Get a specific audit report
 */

export function useGetReport<
  TData = Awaited<ReturnType<typeof getReport>>,
  TError = ErrorType<unknown>,
>(
  reportId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getReport>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetReportQueryOptions(reportId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
